import{c as t,Q as a,j as r,m as o}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"鼠标光标偏移","description":"","frontmatter":{"title":"鼠标光标偏移"},"headers":[],"relativePath":"notes/030/mouse_cursor_offset.md","filePath":"notes/030/mouse_cursor_offset.md","lastUpdated":1779686691000}'),s={name:"notes/030/mouse_cursor_offset.md"};function i(l,e,d,n,u,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_030-鼠标光标偏移排查" tabindex="-1">030 鼠标光标偏移排查 <a class="header-anchor" href="#_030-鼠标光标偏移排查" aria-label="Permalink to &quot;030 鼠标光标偏移排查&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>QEMU VNC 中显示两个光标：QEMU 自带的圆点 + 我们绘制的箭头。两者之间存在固定偏移，且方向随初始位置设置变化：</p><ul><li>初始化到屏幕中央 <code>(512, 384)</code> → 我们的箭头在 QEMU 圆点的右下方</li><li>初始化到 <code>(0, 0)</code> → 我们的箭头在 QEMU 圆点的左上方</li><li>偏移量约等于初始位置坐标值，不随鼠标移动改变</li></ul><h2 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h2><p><strong>PS/2 协议只报告相对位移（dx/dy），不报告绝对位置。</strong></p><p>QEMU 的 VNC 光标覆盖层使用宿主机的绝对坐标渲染。Guest OS（我们）通过累积 PS/2 dx/dy 从初始位置推算光标位置。两者从不同起点出发，累积相同的位移，因此偏移恒等于初始位置的差值。</p><p>这不是代码 bug，而是 PS/2 鼠标在 VM 中的已知固有缺陷。</p><h2 id="尝试过的方案" tabindex="-1">尝试过的方案 <a class="header-anchor" href="#尝试过的方案" aria-label="Permalink to &quot;尝试过的方案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>结果</th></tr></thead><tbody><tr><td>初始化到屏幕中央</td><td>偏移 ≈ (512, 384)，方向不一致</td></tr><tr><td>初始化到 (0, 0)</td><td>偏移减小但仍然存在，方向反转</td></tr><tr><td>修改 bitmap 像素值</td><td>只影响箭头形状，不影响位置</td></tr><tr><td><code>-display default,show-cursor=off</code></td><td>QEMU 只编译了 <code>none</code> 后端，该选项无效</td></tr><tr><td><code>-display gtk,show-cursor=off</code></td><td>用户环境无 GTK</td></tr><tr><td><code>-usb -device usb-tablet</code></td><td><strong>有效</strong> — VNC 光标使用绝对定位，鼠标不再卡住</td></tr></tbody></table><h2 id="最终方案" tabindex="-1">最终方案 <a class="header-anchor" href="#最终方案" aria-label="Permalink to &quot;最终方案&quot;">​</a></h2><ol><li><strong>QEMU 配置</strong>：添加 <code>-usb -device usb-tablet</code>，VNC 光标使用绝对坐标，解决鼠标抓取卡住问题</li><li><strong>Guest 初始位置</strong>：<code>mouse_x_ = 0, mouse_y_ = 0</code>，用户从左上角手动移入对齐</li><li><strong>长期方案</strong>：实现 USB HID 驱动，读取 USB tablet 的绝对坐标，彻底消除双光标偏移</li></ol><h2 id="技术背景" tabindex="-1">技术背景 <a class="header-anchor" href="#技术背景" aria-label="Permalink to &quot;技术背景&quot;">​</a></h2><h3 id="为什么-ps-2-无法与宿主光标对齐" tabindex="-1">为什么 PS/2 无法与宿主光标对齐 <a class="header-anchor" href="#为什么-ps-2-无法与宿主光标对齐" aria-label="Permalink to &quot;为什么 PS/2 无法与宿主光标对齐&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>宿主机: cursor = (absolute_x, absolute_y)  ← VNC 客户端直接知道</span></span>\n<span class="line"><span>Guest:  cursor = (init_x + Σdx, init_y + Σdy)  ← 只能累积位移</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>两者之间没有同步机制。PS/2 协议（1980s 设计）没有 &quot;get absolute position&quot; 命令。</p><h3 id="为什么-device-usb-tablet-有效" tabindex="-1">为什么 <code>-device usb-tablet</code> 有效 <a class="header-anchor" href="#为什么-device-usb-tablet-有效" aria-label="Permalink to &quot;为什么 `-device usb-tablet` 有效&quot;">​</a></h3><p>USB HID Tablet 设备通过 HID Absolute Pointer 用途报告绝对坐标 (0~width, 0~height)。QEMU 将宿主鼠标的绝对位置直接映射到 tablet 坐标，Guest OS 如果有 USB HID 驱动就能读到精确位置。</p><p>当前我们没有 USB 驱动，但 QEMU 在宿主侧处理 tablet，VNC 光标仍然用绝对定位渲染，解决了鼠标抓取问题。两个光标仍然独立，但不影响可用性。</p><h3 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h3><ul><li><a href="https://torgeir.dev/2024/02/qemu-mouse-cursor-offset/" target="_blank" rel="noreferrer">QEMU Mouse Cursor Offset</a></li><li><a href="https://wiki.archlinux.org/title/QEMU/Troubleshooting" target="_blank" rel="noreferrer">ArchWiki: QEMU/Troubleshooting</a></li><li><a href="https://gitlab.com/qemu-project/qemu/-/issues/2225" target="_blank" rel="noreferrer">QEMU GitLab #2225: Mouse capture issue</a></li></ul>',21)])])}const p=t(s,[["render",i]]);export{b as __pageData,p as default};
